import { z } from 'zod'
import * as fs from 'node:fs'
import * as path from 'node:path'
import * as os from 'node:os'
import { log } from './log.js'

const TelegramChannelSchema = z.object({
  enabled: z.boolean().default(false),
  botToken: z.string(),
  chatId: z.number(),
  notificationTopicId: z.number().nullable().default(null),
  assistantTopicId: z.number().nullable().default(null),
}).optional()

const AgentSchema = z.object({
  command: z.string(),
  args: z.array(z.string()).default([]),
  workingDirectory: z.string().optional(),
  env: z.record(z.string(), z.string()).default({}),
})

export const ConfigSchema = z.object({
  channels: z.object({
    telegram: TelegramChannelSchema,
  }),
  agents: z.record(z.string(), AgentSchema),
  defaultAgent: z.string(),
  workspace: z.object({
    baseDir: z.string().default('~/openacp-workspace'),
  }).default({}),
  security: z.object({
    allowedUserIds: z.array(z.string()).default([]),
    maxConcurrentSessions: z.number().default(5),
    sessionTimeoutMinutes: z.number().default(60),
  }).default({}),
})

export type Config = z.infer<typeof ConfigSchema>

export function expandHome(p: string): string {
  if (p.startsWith('~')) {
    return path.join(os.homedir(), p.slice(1))
  }
  return p
}

const DEFAULT_CONFIG = {
  channels: {
    telegram: {
      enabled: false,
      botToken: "YOUR_BOT_TOKEN_HERE",
      chatId: 0,
      notificationTopicId: null,
      assistantTopicId: null
    }
  },
  agents: {
    claude: { command: "claude-agent-acp", args: [], env: {} },
    codex: { command: "codex", args: ["--acp"], env: {} }
  },
  defaultAgent: "claude",
  workspace: { baseDir: "~/openacp-workspace" },
  security: { allowedUserIds: [], maxConcurrentSessions: 5, sessionTimeoutMinutes: 60 }
}

export class ConfigManager {
  private config!: Config
  private configPath: string

  constructor() {
    this.configPath = process.env.OPENACP_CONFIG_PATH || expandHome('~/.openacp/config.json')
  }

  async load(): Promise<void> {
    // 1. Ensure directory exists
    const dir = path.dirname(this.configPath)
    fs.mkdirSync(dir, { recursive: true })

    // 2. If config file doesn't exist, create default
    if (!fs.existsSync(this.configPath)) {
      fs.writeFileSync(this.configPath, JSON.stringify(DEFAULT_CONFIG, null, 2))
      log.info(`Config created at ${this.configPath}`)
      log.info('Please edit it with your Telegram bot token and chat ID, then restart.')
      process.exit(1)
    }

    // 3. Read and parse
    const raw = JSON.parse(fs.readFileSync(this.configPath, 'utf-8'))

    // 4. Apply env var overrides
    this.applyEnvOverrides(raw)

    // 5. Validate with Zod
    const result = ConfigSchema.safeParse(raw)
    if (!result.success) {
      log.error('Config validation failed:')
      for (const issue of result.error.issues) {
        log.error(`  ${issue.path.join('.')}: ${issue.message}`)
      }
      process.exit(1)
    }
    this.config = result.data
  }

  get(): Config {
    return this.config
  }

  async save(updates: Record<string, unknown>): Promise<void> {
    // Read current file, merge updates, write back
    const raw = JSON.parse(fs.readFileSync(this.configPath, 'utf-8'))
    this.deepMerge(raw, updates)
    fs.writeFileSync(this.configPath, JSON.stringify(raw, null, 2))
    // Re-validate and update in-memory config
    const result = ConfigSchema.safeParse(raw)
    if (result.success) {
      this.config = result.data
    }
  }

  resolveWorkspace(input?: string): string {
    if (!input) {
      const resolved = expandHome(this.config.workspace.baseDir)
      fs.mkdirSync(resolved, { recursive: true })
      return resolved
    }
    if (input.startsWith('/') || input.startsWith('~')) {
      const resolved = expandHome(input)
      fs.mkdirSync(resolved, { recursive: true })
      return resolved
    }
    // Named workspace → lowercase, under baseDir
    const name = input.toLowerCase()
    const resolved = path.join(expandHome(this.config.workspace.baseDir), name)
    fs.mkdirSync(resolved, { recursive: true })
    return resolved
  }

  private applyEnvOverrides(raw: Record<string, unknown>): void {
    const overrides: [string, string[]][] = [
      ['OPENACP_TELEGRAM_BOT_TOKEN', ['channels', 'telegram', 'botToken']],
      ['OPENACP_TELEGRAM_CHAT_ID', ['channels', 'telegram', 'chatId']],
      ['OPENACP_DEFAULT_AGENT', ['defaultAgent']],
    ]
    for (const [envVar, configPath] of overrides) {
      const value = process.env[envVar]
      if (value !== undefined) {
        let target = raw as Record<string, any>
        for (let i = 0; i < configPath.length - 1; i++) {
          if (!target[configPath[i]]) target[configPath[i]] = {}
          target = target[configPath[i]]
        }
        const key = configPath[configPath.length - 1]
        // Convert chatId to number
        target[key] = key === 'chatId' ? Number(value) : value
      }
    }
  }

  private deepMerge(target: Record<string, any>, source: Record<string, any>): void {
    for (const key of Object.keys(source)) {
      if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
        if (!target[key]) target[key] = {}
        this.deepMerge(target[key], source[key])
      } else {
        target[key] = source[key]
      }
    }
  }
}

#!/usr/bin/env node

import { ConfigManager } from './config.js'
import { OpenACPCore } from './core.js'
import { log } from './log.js'

let shuttingDown = false

async function main() {
  // 1. Load config
  const configManager = new ConfigManager()
  await configManager.load()  // exits if config missing/invalid

  const config = configManager.get()
  log.info('Config loaded from', configManager['configPath'])

  // 2. Create core
  const core = new OpenACPCore(configManager)

  // 3. Register enabled adapters
  if (config.channels.telegram?.enabled) {
    // Resolve adapter from workspace root (not from core's node_modules, to avoid circular dep)
    const adapterPath = new URL('../../adapters/telegram/dist/index.js', import.meta.url).pathname
    // @ts-ignore — dynamic path import
    const { TelegramAdapter } = await import(adapterPath)
    core.registerAdapter('telegram', new TelegramAdapter(core, config.channels.telegram))
    log.info('Telegram adapter registered')
  }

  if (core.adapters.size === 0) {
    log.error('No channels enabled. Enable at least one channel in config.')
    process.exit(1)
  }

  // 4. Start
  await core.start()

  // 5. Log ready
  const agents = Object.keys(config.agents).join(', ')
  log.info(`OpenACP started. Agents: ${agents}`)
  log.info('Press Ctrl+C to stop.')

  // 6. Graceful shutdown
  const shutdown = async (signal: string) => {
    if (shuttingDown) return
    shuttingDown = true
    log.info(`${signal} received. Shutting down...`)

    try {
      await core.stop()
    } catch (err) {
      log.error('Error during shutdown:', err)
    }

    process.exit(0)
  }

  process.on('SIGINT', () => shutdown('SIGINT'))
  process.on('SIGTERM', () => shutdown('SIGTERM'))

  process.on('uncaughtException', (err) => {
    log.error('Uncaught exception:', err)
  })

  process.on('unhandledRejection', (err) => {
    log.error('Unhandled rejection:', err)
  })
}

main().catch((err) => {
  log.error('Fatal:', err)
  process.exit(1)
})

{
  "compilerOptions": {
    "target": "ES2022",
    "module": "NodeNext",
    "moduleResolution": "NodeNext",
    "strict": true,
    "esModuleInterop": true,
    "declaration": true,
    "declarationMap": true,
    "sourceMap": true,
    "skipLibCheck": true
  }
}

import { ConfigManager } from './config.js'
import { AgentManager } from './agent-manager.js'
import { SessionManager } from './session-manager.js'
import { NotificationManager } from './notification.js'
import { ChannelAdapter } from './channel.js'
import { Session } from './session.js'
import type { IncomingMessage, AgentEvent, OutgoingMessage, PermissionRequest } from './types.js'
import { log } from './log.js'

export class OpenACPCore {
  configManager: ConfigManager
  agentManager: AgentManager
  sessionManager: SessionManager
  notificationManager: NotificationManager
  adapters: Map<string, ChannelAdapter> = new Map()

  constructor(configManager: ConfigManager) {
    this.configManager = configManager
    const config = configManager.get()
    this.agentManager = new AgentManager(config)
    this.sessionManager = new SessionManager()
    this.notificationManager = new NotificationManager(this.adapters)
  }

  registerAdapter(name: string, adapter: ChannelAdapter): void {
    this.adapters.set(name, adapter)
  }

  async start(): Promise<void> {
    for (const adapter of this.adapters.values()) {
      await adapter.start()
    }
  }

  async stop(): Promise<void> {
    // 1. Notify users
    try {
      await this.notificationManager.notifyAll({
        sessionId: 'system',
        type: 'error',
        summary: 'OpenACP is shutting down',
      })
    } catch { /* best effort */ }

    // 2. Destroy all sessions
    await this.sessionManager.destroyAll()

    // 3. Stop adapters
    for (const adapter of this.adapters.values()) {
      await adapter.stop()
    }
  }

  // --- Message Routing ---

  async handleMessage(message: IncomingMessage): Promise<void> {
    const config = this.configManager.get()

    // Security: check allowed user IDs
    if (config.security.allowedUserIds.length > 0) {
      if (!config.security.allowedUserIds.includes(message.userId)) return
    }

    // Check concurrent session limit
    const activeSessions = this.sessionManager.listSessions()
      .filter(s => s.status === 'active' || s.status === 'initializing')
    if (activeSessions.length >= config.security.maxConcurrentSessions) {
      const adapter = this.adapters.get(message.channelId)
      if (adapter) {
        await adapter.sendMessage('system', {
          type: 'error',
          text: `Max concurrent sessions (${config.security.maxConcurrentSessions}) reached. Cancel a session first.`,
        })
      }
      return
    }

    // Find session by thread
    const session = this.sessionManager.getSessionByThread(message.channelId, message.threadId)
    if (!session) return

    // Forward to session
    await session.enqueuePrompt(message.text)
  }

  async handleNewSession(
    channelId: string,
    agentName?: string,
    workspacePath?: string,
  ): Promise<Session> {
    const config = this.configManager.get()
    const resolvedAgent = agentName || config.defaultAgent
    const resolvedWorkspace = this.configManager.resolveWorkspace(
      workspacePath || config.agents[resolvedAgent]?.workingDirectory
    )

    const session = await this.sessionManager.createSession(
      channelId, resolvedAgent, resolvedWorkspace, this.agentManager
    )

    // Wire events
    const adapter = this.adapters.get(channelId)
    if (adapter) {
      this.wireSessionEvents(session, adapter)
    }

    return session
  }

  async handleNewChat(
    channelId: string,
    currentThreadId: string,
  ): Promise<Session | null> {
    const currentSession = this.sessionManager.getSessionByThread(channelId, currentThreadId)
    if (!currentSession) return null

    return this.handleNewSession(
      channelId,
      currentSession.agentName,
      currentSession.workingDirectory,
    )
  }

  // --- Event Wiring ---

  private toOutgoingMessage(event: AgentEvent): OutgoingMessage {
    switch (event.type) {
      case 'text':
        return { type: 'text', text: event.content }
      case 'thought':
        return { type: 'thought', text: event.content }
      case 'tool_call':
        return { type: 'tool_call', text: event.name, metadata: { id: event.id, kind: event.kind, status: event.status, content: event.content, locations: event.locations } }
      case 'tool_update':
        return { type: 'tool_update', text: '', metadata: { id: event.id, status: event.status, content: event.content } }
      case 'plan':
        return { type: 'plan', text: '', metadata: { entries: event.entries } }
      case 'usage':
        return { type: 'usage', text: '', metadata: { tokensUsed: event.tokensUsed, contextSize: event.contextSize, cost: event.cost } }
      case 'commands_update':
        // Log but don't surface to user (Phase 3 feature)
        log.debug('Commands update:', event.commands)
        return { type: 'text', text: '' }  // no-op for now
      default:
        return { type: 'text', text: '' }
    }
  }

  // Public — adapters call this for assistant session wiring
  wireSessionEvents(session: Session, adapter: ChannelAdapter): void {
    // Set adapter reference for autoName → renameSessionThread
    session.adapter = adapter

    session.agentInstance.onSessionUpdate = (event: AgentEvent) => {
      switch (event.type) {
        case 'text':
        case 'thought':
        case 'tool_call':
        case 'tool_update':
        case 'plan':
        case 'usage':
          adapter.sendMessage(session.id, this.toOutgoingMessage(event))
          break

        case 'session_end':
          session.status = 'finished'
          adapter.sendMessage(session.id, { type: 'session_end', text: `Done (${event.reason})` })
          this.notificationManager.notify(session.channelId, {
            sessionId: session.id,
            sessionName: session.name,
            type: 'completed',
            summary: `Session "${session.name || session.id}" completed`,
          })
          break

        case 'error':
          adapter.sendMessage(session.id, { type: 'error', text: event.message })
          this.notificationManager.notify(session.channelId, {
            sessionId: session.id,
            sessionName: session.name,
            type: 'error',
            summary: event.message,
          })
          break

        case 'commands_update':
          log.debug('Commands available:', event.commands)
          break
      }
    }

    session.agentInstance.onPermissionRequest = async (request: PermissionRequest) => {
      // Send permission UI to session topic
      await adapter.sendPermissionRequest(session.id, request)

      // Send notification with deep link
      await this.notificationManager.notify(session.channelId, {
        sessionId: session.id,
        sessionName: session.name,
        type: 'permission',
        summary: request.description,
      })

      // Wait for user response — adapter resolves this promise
      return new Promise<string>((resolve) => {
        session.pendingPermission = { requestId: request.id, resolve }
      })
    }
  }
}

