     1→import { spawn, execSync, type ChildProcess } from 'node:child_process'
     2→import fs from 'node:fs'
     3→import path from 'node:path'
     4→import { randomUUID } from 'node:crypto'
     5→import { ClientSideConnection, ndJsonStream } from '@agentclientprotocol/sdk'
     6→import type { Agent, Client, PromptResponse, PermissionOption as SdkPermissionOption } from '@agentclientprotocol/sdk'
     7→import { nodeToWebWritable, nodeToWebReadable } from './streams.js'
     8→import { StderrCapture } from './stderr-capture.js'
     9→import type { AgentDefinition, AgentEvent, PermissionRequest } from './types.js'
    10→import { log } from './log.js'
    11→
    12→/** Resolve an agent command to a directly executable form (avoids shell wrappers) */
    13→function resolveAgentCommand(cmd: string): { command: string; args: string[] } {
    14→  // 1. Check local node_modules for the package's actual JS entry point
    15→  const packageDirs = [
    16→    path.resolve(process.cwd(), 'node_modules', '@zed-industries', cmd, 'dist', 'index.js'),
    17→    path.resolve(process.cwd(), 'node_modules', cmd, 'dist', 'index.js'),
    18→  ]
    19→  for (const jsPath of packageDirs) {
    20→    if (fs.existsSync(jsPath)) {
    21→      return { command: process.execPath, args: [jsPath] }
    22→    }
    23→  }
    24→
    25→  // 2. Check local .bin — if it's a JS file with shebang, run with node directly
    26→  const localBin = path.resolve(process.cwd(), 'node_modules', '.bin', cmd)
    27→  if (fs.existsSync(localBin)) {
    28→    const content = fs.readFileSync(localBin, 'utf-8')
    29→    if (content.startsWith('#!/usr/bin/env node')) {
    30→      return { command: process.execPath, args: [localBin] }
    31→    }
    32→    // Shell wrapper — try to find the target JS file
    33→    const match = content.match(/"([^"]+\.js)"/)
    34→    if (match) {
    35→      const target = path.resolve(path.dirname(localBin), match[1])
    36→      if (fs.existsSync(target)) {
    37→        return { command: process.execPath, args: [target] }
    38→      }
    39→    }
    40→  }
    41→
    42→  // 3. Try resolving from PATH using which
    43→  try {
    44→    const fullPath = execSync(`which ${cmd}`, { encoding: 'utf-8' }).trim()
    45→    if (fullPath) {
    46→      const content = fs.readFileSync(fullPath, 'utf-8')
    47→      if (content.startsWith('#!/usr/bin/env node')) {
    48→        return { command: process.execPath, args: [fullPath] }
    49→      }
    50→    }
    51→  } catch {
    52→    // which failed
    53→  }
    54→
    55→  // 4. Fallback: use command as-is
    56→  return { command: cmd, args: [] }
    57→}
    58→
    59→interface TerminalState {
    60→  process: ChildProcess
    61→  output: string
    62→  exitStatus: { exitCode: number | null; signal: string | null } | null
    63→}
    64→
    65→export class AgentInstance {
    66→  private connection!: ClientSideConnection
    67→  private child!: ChildProcess
    68→  private stderrCapture!: StderrCapture
    69→  private terminals: Map<string, TerminalState> = new Map()
    70→
    71→  sessionId!: string
    72→  agentName: string
    73→
    74→  // Callbacks — set by core when wiring events
    75→  onSessionUpdate: (event: AgentEvent) => void = () => {}
    76→  onPermissionRequest: (request: PermissionRequest) => Promise<string> = async () => ''
    77→
    78→  private constructor(agentName: string) {
    79→    this.agentName = agentName
    80→  }
    81→
    82→  static async spawn(agentDef: AgentDefinition, workingDirectory: string): Promise<AgentInstance> {
    83→    const instance = new AgentInstance(agentDef.name)
    84→
    85→    // 1. Resolve command: find the actual JS entry point to avoid shell wrappers
    86→    const resolved = resolveAgentCommand(agentDef.command)
    87→    log.debug(`Spawning agent "${agentDef.name}" → ${resolved.command} ${resolved.args.join(' ')}`)
    88→
    89→    // Spawn subprocess
    90→    instance.child = spawn(resolved.command, [...resolved.args, ...agentDef.args], {
    91→      stdio: ['pipe', 'pipe', 'pipe'],
    92→      cwd: workingDirectory,
    93→      env: { ...process.env, ...agentDef.env },
    94→    })
    95→
    96→    // 2. Handle spawn errors (e.g., command not found)
    97→    await new Promise<void>((resolve, reject) => {
    98→      instance.child.on('error', (err) => {
    99→        reject(new Error(`Failed to spawn agent "${agentDef.name}": ${err.message}. Is "${agentDef.command}" installed?`))
   100→      })
   101→      instance.child.on('spawn', () => resolve())
   102→    })
   103→
   104→    // 3. Capture stderr
   105→    instance.stderrCapture = new StderrCapture(50)
   106→    instance.child.stderr!.on('data', (chunk: Buffer) => {
   107→      instance.stderrCapture.append(chunk.toString())
   108→    })
   109→
   110→    // 3. Create ACP stream
   111→    const toAgent = nodeToWebWritable(instance.child.stdin!)
   112→    const fromAgent = nodeToWebReadable(instance.child.stdout!)
   113→    const stream = ndJsonStream(toAgent, fromAgent)
   114→
   115→    // 4. Create ClientSideConnection
   116→    instance.connection = new ClientSideConnection(
   117→      (_agent: Agent): Client => instance.createClient(_agent),
   118→      stream,
   119→    )
   120→
   121→    // 5. ACP handshake
   122→    await instance.connection.initialize({
   123→      protocolVersion: 1,
   124→      clientCapabilities: {
   125→        fs: { readTextFile: true, writeTextFile: true },
   126→        terminal: true,
   127→      },
   128→    })
   129→
   130→    // 6. Create session
   131→    const response = await instance.connection.newSession({
   132→      cwd: workingDirectory,
   133→      mcpServers: [],
   134→    })
   135→    instance.sessionId = response.sessionId
   136→
   137→    // 7. Crash detection
   138→    instance.child.on('exit', (code, signal) => {
   139→      if (code !== 0 && code !== null) {
   140→        const stderr = instance.stderrCapture.getLastLines()
   141→        instance.onSessionUpdate({
   142→          type: 'error',
   143→          message: `Agent crashed (exit code ${code})\n${stderr}`,
   144→        })
   145→      }
   146→    })
   147→
   148→    instance.connection.closed.then(() => {
   149→      // Connection closed — may be normal shutdown or crash
   150→      log.debug('ACP connection closed for', instance.agentName)
   151→    })
   152→
   153→    log.info(`Agent "${agentDef.name}" spawned with session ${response.sessionId}`)
   154→    return instance
   155→  }
   156→
   157→  // createClient — implemented in Task 6b
   158→  private createClient(_agent: Agent): Client {
   159→    const self = this
   160→    const MAX_OUTPUT_BYTES = 1024 * 1024 // 1MB cap
   161→
   162→    return {
   163→      // ── Session updates ──────────────────────────────────────────────────
   164→      async sessionUpdate(params) {
   165→        const update = params.update
   166→        let event: AgentEvent | null = null
   167→
   168→        switch (update.sessionUpdate) {
   169→          case 'agent_message_chunk':
   170→            if (update.content.type === 'text') {
   171→              event = { type: 'text', content: update.content.text }
   172→            }
   173→            break
   174→          case 'agent_thought_chunk':
   175→            if (update.content.type === 'text') {
   176→              event = { type: 'thought', content: update.content.text }
   177→            }
   178→            break
   179→          case 'tool_call':
   180→            event = {
   181→              type: 'tool_call',
   182→              id: update.toolCallId,
   183→              name: update.title,
   184→              kind: update.kind ?? undefined,
   185→              status: update.status ?? 'pending',
   186→            }
   187→            break
   188→          case 'tool_call_update':
   189→            event = {
   190→              type: 'tool_update',
   191→              id: update.toolCallId,
   192→              status: update.status ?? 'pending',
   193→            }
   194→            break
   195→          case 'plan':
   196→            event = { type: 'plan', entries: update.entries }
   197→            break
   198→          case 'usage_update':
   199→            event = {
   200→              type: 'usage',
   201→              tokensUsed: update.used,
   202→              contextSize: update.size,
   203→              cost: update.cost ?? undefined,
   204→            }
   205→            break
   206→          case 'available_commands_update':
   207→            event = { type: 'commands_update', commands: update.availableCommands }
   208→            break
   209→          default:
   210→            // Unknown update type — ignore
   211→            return
   212→        }
   213→
   214→        if (event !== null) {
   215→          self.onSessionUpdate(event)
   216→        }
   217→      },
   218→
   219→      // ── Permission requests ──────────────────────────────────────────────
   220→      async requestPermission(params) {
   221→        const permissionRequest: PermissionRequest = {
   222→          id: params.toolCall.toolCallId,
   223→          description: params.toolCall.title ?? params.toolCall.toolCallId,
   224→          options: params.options.map((opt: SdkPermissionOption) => ({
   225→            id: opt.optionId,
   226→            label: opt.name,
   227→            isAllow: opt.kind === 'allow_once' || opt.kind === 'allow_always',
   228→          })),
   229→        }
   230→
   231→        const selectedOptionId = await self.onPermissionRequest(permissionRequest)
   232→        return {
   233→          outcome: { outcome: 'selected' as const, optionId: selectedOptionId },
   234→        }
   235→      },
   236→
   237→      // ── File operations ──────────────────────────────────────────────────
   238→      async readTextFile(params) {
   239→        const content = await fs.promises.readFile(params.path, 'utf-8')
   240→        return { content }
   241→      },
   242→
   243→      async writeTextFile(params) {
   244→        await fs.promises.mkdir(path.dirname(params.path), { recursive: true })
   245→        await fs.promises.writeFile(params.path, params.content, 'utf-8')
   246→        return {}
   247→      },
   248→
   249→      // ── Terminal operations ──────────────────────────────────────────────
   250→      async createTerminal(params) {
   251→        const terminalId = randomUUID()
   252→        const args = params.args ?? []
   253→        const env: Record<string, string> = {}
   254→        for (const ev of params.env ?? []) {
   255→          env[ev.name] = ev.value
   256→        }
   257→
   258→        const childProcess = spawn(params.command, args, {
   259→          cwd: params.cwd ?? undefined,
   260→          env: { ...process.env, ...env },
   261→          shell: false,
   262→        })
   263→
   264→        const state: TerminalState = {
   265→          process: childProcess,
   266→          output: '',
   267→          exitStatus: null,
   268→        }
   269→        self.terminals.set(terminalId, state)
   270→
   271→        const outputByteLimit = params.outputByteLimit ?? MAX_OUTPUT_BYTES
   272→
   273→        const appendOutput = (chunk: string) => {
   274→          state.output += chunk
   275→          // Truncate from the beginning if over limit
   276→          const bytes = Buffer.byteLength(state.output, 'utf-8')
   277→          if (bytes > outputByteLimit) {
   278→            // Find truncation point at character boundary
   279→            const excess = bytes - outputByteLimit
   280→            state.output = state.output.slice(excess)
   281→          }
   282→        }
   283→
   284→        childProcess.stdout?.on('data', (chunk: Buffer) => appendOutput(chunk.toString()))
   285→        childProcess.stderr?.on('data', (chunk: Buffer) => appendOutput(chunk.toString()))
   286→
   287→        childProcess.on('exit', (code, signal) => {
   288→          state.exitStatus = { exitCode: code, signal }
   289→        })
   290→
   291→        return { terminalId }
   292→      },
   293→
   294→      async terminalOutput(params) {
   295→        const state = self.terminals.get(params.terminalId)
   296→        if (!state) {
   297→          throw new Error(`Terminal not found: ${params.terminalId}`)
   298→        }
   299→        return {
   300→          output: state.output,
   301→          truncated: false,
   302→          exitStatus: state.exitStatus
   303→            ? { exitCode: state.exitStatus.exitCode, signal: state.exitStatus.signal }
   304→            : undefined,
   305→        }
   306→      },
   307→
   308→      async waitForTerminalExit(params) {
   309→        const state = self.terminals.get(params.terminalId)
   310→        if (!state) {
   311→          throw new Error(`Terminal not found: ${params.terminalId}`)
   312→        }
   313→        if (state.exitStatus !== null) {
   314→          return { exitCode: state.exitStatus.exitCode, signal: state.exitStatus.signal }
   315→        }
   316→        return new Promise((resolve) => {
   317→          state.process.on('exit', (code, signal) => {
   318→            resolve({ exitCode: code, signal })
   319→          })
   320→        })
   321→      },
   322→
   323→      async killTerminal(params) {
   324→        const state = self.terminals.get(params.terminalId)
   325→        if (!state) {
   326→          throw new Error(`Terminal not found: ${params.terminalId}`)
   327→        }
   328→        state.process.kill('SIGTERM')
   329→        return {}
   330→      },
   331→
   332→      async releaseTerminal(params) {
   333→        const state = self.terminals.get(params.terminalId)
   334→        if (!state) {
   335→          return
   336→        }
   337→        state.process.kill('SIGKILL')
   338→        self.terminals.delete(params.terminalId)
   339→      },
   340→    }
   341→  }
   342→
   343→  async prompt(text: string): Promise<PromptResponse> {
   344→    return this.connection.prompt({
   345→      sessionId: this.sessionId,
   346→      prompt: [{ type: 'text', text }],
   347→    })
   348→  }
   349→
   350→  async cancel(): Promise<void> {
   351→    await this.connection.cancel({ sessionId: this.sessionId })
   352→  }
   353→
   354→  async destroy(): Promise<void> {
   355→    // Cleanup terminals
   356→    for (const [, t] of this.terminals) {
   357→      t.process.kill('SIGKILL')
   358→    }
   359→    this.terminals.clear()
   360→
   361→    // Kill agent subprocess
   362→    this.child.kill('SIGTERM')
   363→    setTimeout(() => {
   364→      if (!this.child.killed) this.child.kill('SIGKILL')
   365→    }, 10_000)
   366→  }
   367→}
   368→

