     1→import { Bot } from 'grammy'
     2→import { ChannelAdapter, type OpenACPCore, type OutgoingMessage, type PermissionRequest, type NotificationMessage, type Session, log } from '@openacp/core'
     3→import type { TelegramChannelConfig } from './types.js'
     4→import { MessageDraft } from './streaming.js'
     5→import { ensureTopics, createSessionTopic, renameSessionTopic } from './topics.js'
     6→import { setupCommands } from './commands.js'
     7→import { PermissionHandler } from './permissions.js'
     8→import { spawnAssistant, handleAssistantMessage, redirectToAssistant } from './assistant.js'
     9→import { escapeHtml, formatToolCall, formatToolUpdate, formatPlan, formatUsage } from './formatting.js'
    10→
    11→export class TelegramAdapter extends ChannelAdapter {
    12→  private bot!: Bot
    13→  private telegramConfig: TelegramChannelConfig
    14→  private sessionDrafts: Map<string, MessageDraft> = new Map()
    15→  private toolCallMessages: Map<string, Map<string, number>> = new Map()  // sessionId → (toolCallId → msgId)
    16→  private permissionHandler!: PermissionHandler
    17→  private assistantSession: Session | null = null
    18→  private notificationTopicId!: number
    19→  private assistantTopicId!: number
    20→
    21→  constructor(core: OpenACPCore, config: TelegramChannelConfig) {
    22→    super(core, config as any)
    23→    this.telegramConfig = config
    24→  }
    25→
    26→  async start(): Promise<void> {
    27→    this.bot = new Bot(this.telegramConfig.botToken)
    28→
    29→    // Middleware: only accept messages from configured chatId
    30→    this.bot.use((ctx, next) => {
    31→      if (ctx.chat?.id !== this.telegramConfig.chatId) return
    32→      return next()
    33→    })
    34→
    35→    // Ensure system topics exist
    36→    const topics = await ensureTopics(
    37→      this.bot,
    38→      this.telegramConfig.chatId,
    39→      this.telegramConfig,
    40→      async (updates) => {
    41→        // Save topic IDs to config
    42→        await (this.core as OpenACPCore).configManager.save({
    43→          channels: { telegram: updates }
    44→        })
    45→      }
    46→    )
    47→    this.notificationTopicId = topics.notificationTopicId
    48→    this.assistantTopicId = topics.assistantTopicId
    49→
    50→    // Setup permission handler
    51→    this.permissionHandler = new PermissionHandler(
    52→      this.bot,
    53→      this.telegramConfig.chatId,
    54→      (sessionId) => (this.core as OpenACPCore).sessionManager.getSession(sessionId),
    55→      (notification) => this.sendNotification(notification),
    56→    )
    57→    this.permissionHandler.setupCallbackHandler()
    58→
    59→    // Setup commands
    60→    setupCommands(this.bot, this.core as OpenACPCore, this.telegramConfig.chatId)
    61→
    62→    // Setup message routing
    63→    this.setupRoutes()
    64→
    65→    // Start bot polling
    66→    this.bot.start({
    67→      allowed_updates: ['message', 'callback_query'],
    68→      onStart: () => log.info('Telegram bot started'),
    69→    })
    70→
    71→    // Spawn assistant (after bot is started so it can send messages)
    72→    try {
    73→      this.assistantSession = await spawnAssistant(
    74→        this.core as OpenACPCore,
    75→        this,
    76→        this.assistantTopicId,
    77→      )
    78→    } catch (err) {
    79→      log.error('Failed to spawn assistant:', err)
    80→    }
    81→  }
    82→
    83→  async stop(): Promise<void> {
    84→    if (this.assistantSession) {
    85→      await this.assistantSession.destroy()
    86→    }
    87→    await this.bot.stop()
    88→  }
    89→
    90→  private setupRoutes(): void {
    91→    this.bot.on('message:text', async (ctx) => {
    92→      const threadId = ctx.message.message_thread_id
    93→
    94→      // General topic or no thread → redirect to assistant
    95→      if (!threadId) {
    96→        const html = redirectToAssistant(this.telegramConfig.chatId, this.assistantTopicId)
    97→        await ctx.reply(html, { parse_mode: 'HTML' })
    98→        return
    99→      }
   100→
   101→      // Notification topic → ignore
   102→      if (threadId === this.notificationTopicId) return
   103→
   104→      // Assistant topic → forward to assistant session
   105→      if (threadId === this.assistantTopicId) {
   106→        await handleAssistantMessage(this.assistantSession, ctx.message.text)
   107→        return
   108→      }
   109→
   110→      // Session topic → forward to core
   111→      await (this.core as OpenACPCore).handleMessage({
   112→        channelId: 'telegram',
   113→        threadId: String(threadId),
   114→        userId: String(ctx.from.id),
   115→        text: ctx.message.text,
   116→      })
   117→    })
   118→  }
   119→
   120→  // --- ChannelAdapter implementations ---
   121→
   122→  async sendMessage(sessionId: string, content: OutgoingMessage): Promise<void> {
   123→    const session = (this.core as OpenACPCore).sessionManager.getSession(sessionId)
   124→    if (!session) return
   125→    const threadId = Number(session.threadId)
   126→
   127→    switch (content.type) {
   128→      case 'text':
   129→      case 'thought': {
   130→        let draft = this.sessionDrafts.get(sessionId)
   131→        if (!draft) {
   132→          draft = new MessageDraft(this.bot, this.telegramConfig.chatId, threadId)
   133→          this.sessionDrafts.set(sessionId, draft)
   134→        }
   135→        const prefix = content.type === 'thought' ? '💭 ' : ''
   136→        draft.append(prefix + content.text)
   137→        break
   138→      }
   139→
   140→      case 'tool_call': {
   141→        await this.finalizeDraft(sessionId)
   142→        const msg = await this.bot.api.sendMessage(this.telegramConfig.chatId,
   143→          formatToolCall(content.metadata as any),
   144→          { message_thread_id: threadId, parse_mode: 'HTML', disable_notification: true }
   145→        )
   146→        if (!this.toolCallMessages.has(sessionId)) {
