import type { ChannelAdapter } from './channel.js'
import type { NotificationMessage } from './types.js'

export class NotificationManager {
  constructor(private adapters: Map<string, ChannelAdapter>) {}

  async notify(channelId: string, notification: NotificationMessage): Promise<void> {
    const adapter = this.adapters.get(channelId)
    if (adapter) {
      await adapter.sendNotification(notification)
    }
  }

  async notifyAll(notification: NotificationMessage): Promise<void> {
    for (const adapter of this.adapters.values()) {
      await adapter.sendNotification(notification)
    }
  }
}

export const log = {
  info: (...args: unknown[]) => console.log(new Date().toISOString(), '[INFO]', ...args),
  warn: (...args: unknown[]) => console.warn(new Date().toISOString(), '[WARN]', ...args),
  error: (...args: unknown[]) => console.error(new Date().toISOString(), '[ERROR]', ...args),
  debug: (...args: unknown[]) => {
    if (process.env.OPENACP_DEBUG) console.log(new Date().toISOString(), '[DEBUG]', ...args)
  },
}

