import type { Context } from 'grammy'
import type { OpenACPCore, ChannelAdapter, Config } from '@openacp/core'
import type { Session } from '@openacp/core'

export async function spawnAssistant(
  core: OpenACPCore,
  adapter: ChannelAdapter,
  assistantTopicId: number,
): Promise<Session> {
  const config = core.configManager.get()

  // Create session with default agent
  const session = await core.sessionManager.createSession(
    'telegram',
    config.defaultAgent,
    core.configManager.resolveWorkspace(),
    core.agentManager,
  )
  session.threadId = String(assistantTopicId)

  // Wire events to this adapter
  core.wireSessionEvents(session, adapter)

  // Send system prompt
  const systemPrompt = buildAssistantSystemPrompt(config)
  await session.enqueuePrompt(systemPrompt)

  return session
}

export function buildAssistantSystemPrompt(config: Config): string {
  const agentNames = Object.keys(config.agents).join(', ')
  return `You are the OpenACP Assistant. Help users manage their AI coding sessions.

Available agents: ${agentNames}
Default agent: ${config.defaultAgent}
Workspace base: ${config.workspace.baseDir}

When a user wants to create a session, guide them through:
1. Which agent to use
2. Which workspace/project
3. Confirm and create

Commands reference:
- /new [agent] [workspace] — Create new session
- /new_chat — New chat with same agent & workspace
- /cancel — Cancel current session
- /status — Show status
- /agents — List agents
- /help — Show help

Be concise and helpful. When the user confirms session creation, tell them you'll create it now.`
}

export async function handleAssistantMessage(session: Session | null, text: string): Promise<void> {
  if (!session) return
  await session.enqueuePrompt(text)
}

export function redirectToAssistant(chatId: number, assistantTopicId: number): string {
  const cleanId = String(chatId).replace('-100', '')
  const link = `https://t.me/c/${cleanId}/${assistantTopicId}`
  return `💬 Please use the <a href="${link}">🤖 Assistant</a> topic to chat with OpenACP.`
}

import type { Bot } from 'grammy'
import { InlineKeyboard } from 'grammy'
import { nanoid } from 'nanoid'
import type { PermissionRequest, NotificationMessage } from '@openacp/core'
import type { Session } from '@openacp/core'
import { escapeHtml } from './formatting.js'
import { buildDeepLink } from './topics.js'

// Stored pending permission callbacks: callbackKey → { sessionId, requestId }
interface PendingPermission {
  sessionId: string
  requestId: string
}

export class PermissionHandler {
  private pending: Map<string, PendingPermission> = new Map()

  constructor(
    private bot: Bot,
    private chatId: number,
    private getSession: (sessionId: string) => Session | undefined,
    private sendNotification: (notification: NotificationMessage) => Promise<void>,
  ) {}

  async sendPermissionRequest(session: Session, request: PermissionRequest): Promise<void> {
    const threadId = Number(session.threadId)

    // Short callback key (Telegram 64-byte limit on callback_data)
    const callbackKey = nanoid(8)
    this.pending.set(callbackKey, { sessionId: session.id, requestId: request.id })

    // Build inline keyboard
    const keyboard = new InlineKeyboard()
    for (const option of request.options) {
      const emoji = option.isAllow ? '✅' : '❌'
      keyboard.text(`${emoji} ${option.label}`, `p:${callbackKey}:${option.id}`)
    }

    // Send in session topic WITH notification
    const msg = await this.bot.api.sendMessage(this.chatId,
      `🔐 <b>Permission request:</b>\n\n${escapeHtml(request.description)}`,
      {
        message_thread_id: threadId,
        parse_mode: 'HTML',
        reply_markup: keyboard,
        disable_notification: false,
      }
    )

    // Deep link for notification
    const deepLink = buildDeepLink(this.chatId, msg.message_id)

    // Notify in notification topic
    await this.sendNotification({
      sessionId: session.id,
      sessionName: session.name,
      type: 'permission',
      summary: request.description,
      deepLink,
    })
  }

  setupCallbackHandler(): void {
    this.bot.on('callback_query:data', async (ctx) => {
      const data = ctx.callbackQuery.data
      if (!data.startsWith('p:')) return

      const parts = data.split(':')
      if (parts.length < 3) return
      const [, callbackKey, optionId] = parts

      const pending = this.pending.get(callbackKey)
      if (!pending) return

      const session = this.getSession(pending.sessionId)
      if (session?.pendingPermission?.requestId === pending.requestId) {
        session.pendingPermission.resolve(optionId)
        session.pendingPermission = undefined
      }
      this.pending.delete(callbackKey)

      await ctx.answerCallbackQuery({ text: '✅ Responded' })

      // Remove buttons
      try {
        await ctx.editMessageReplyMarkup({ reply_markup: undefined })
      } catch { /* ignore */ }
    })
  }
}

